import{_ as a,o,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Customize QR Codes","description":"","frontmatter":{"title":"Customize QR Codes","slug":"qr-codes-builder"},"headers":[],"relativePath":"marketer-hub/qr-codes-builder.md","filePath":"marketer-hub/qr-codes-builder.md"}'),n={name:"marketer-hub/qr-codes-builder.md"};function i(s,e,l,c,d,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms!</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>QR codes (Quick Response codes) are a great way to advertise your brand and get users to your mobile app easily.</p><p>The <strong>QR Code</strong> <a href="https://dashboard.branch.io/configuration/qr-code" target="_blank" rel="noreferrer">tab</a> of the <strong>Configuration</strong> <a href="https://dashboard.branch.io/configuration/" target="_blank" rel="noreferrer">section</a> of the Branch Dashboard allows you to design and edit your Branch QR Code, so that your company&#39;s branding remains seamless and consistent, whenever and wherever you use Branch Links.</p><h2 id="qr-codes-customization" tabindex="-1">QR Codes Customization <a class="header-anchor" href="#qr-codes-customization" aria-label="Permalink to &quot;QR Codes Customization&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Preview</p><p>Making changes to the configuration will automatically update the preview, which is accessible using the <strong>Preview</strong> button in the top-right corner.</p></div><p>The configurator allows you to edit the following elements of your default Branch QR code:</p><h4 id="style-pattern" tabindex="-1">Style &amp; Pattern <a class="header-anchor" href="#style-pattern" aria-label="Permalink to &quot;Style &amp; Pattern&quot;">​</a></h4><p><strong>Finder Style</strong> lets you change the shape of the three corner elements (top-left, bottom-right, and lower-left) of your QR Code.</p><p><strong>Code Pattern</strong> lets you change the shape of the pattern used for filling out the QR Code.</p><h4 id="color" tabindex="-1">Color <a class="header-anchor" href="#color" aria-label="Permalink to &quot;Color&quot;">​</a></h4><p>You are also able to change the <strong>Code Pattern Color</strong>, <strong>Background Color</strong>, and <strong>Finder Color</strong>. You can either input an HTML color code (hexadecimal triplet) or use the color picker to choose your preferred color.</p><h4 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h4><p>Additionally, you can either input a valid image URL or upload a file (PNG, JPG, JPEG, or SVG) to change your QR Code&#39;s <strong>Center Logo</strong> and/or <strong>Background Image</strong>.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>We recommend using images with transparent backgrounds.</p></div><h4 id="save-reset" tabindex="-1">Save &amp; Reset <a class="header-anchor" href="#save-reset" aria-label="Permalink to &quot;Save &amp; Reset&quot;">​</a></h4><p>When you are satisfied with the result of your customization, you can click the blue <strong>Save</strong> button to confirm your edit, and any newly generate QR Codes created via the Branch QR Code API will have your new design.</p><p>Alternatively, if you wish to start over, you may click the <strong>Reset</strong> button to change the settings back to their original state.</p><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h4 id="customizing-for-scan-reliability" tabindex="-1">Customizing for Scan Reliability <a class="header-anchor" href="#customizing-for-scan-reliability" aria-label="Permalink to &quot;Customizing for Scan Reliability&quot;">​</a></h4><p>The Branch QR Code can be customized with different colors and logos. These customizations may impact a camera&#39;s ability to interpret the Branch QR Code being scanned.</p><p>When creating your Branch QR Code, consider the contrast level of your Branch QR Code. Contrast is an important factor in scan reliability. For example, a dark code color on a light background is a safe display option because it would be high contrast.</p><h5 id="qr-code-physical-sizing" tabindex="-1">QR Code Physical Sizing <a class="header-anchor" href="#qr-code-physical-sizing" aria-label="Permalink to &quot;QR Code Physical Sizing&quot;">​</a></h5><p>Branch QR Code’s physical sizing should be determined by the QR code&#39;s scanning distance and the data to be encoded. The ratio of the scanning distance to the size of the QR code should be close to 10:1, and you can use the following basic rule as described by <a href="https://scanova.io/blog/qr-code-minimum-size/" target="_blank" rel="noreferrer">scanova.io</a>.</p><h5 id="file-format-best-practices" tabindex="-1">File Format Best Practices <a class="header-anchor" href="#file-format-best-practices" aria-label="Permalink to &quot;File Format Best Practices&quot;">​</a></h5><p>Branch QR Codes are designed to be high resolution - any file format you download from the Branch Dashboard will give you a Branch QR Code with a resolution of <strong>300 pixels per inch (DPI)</strong> and an image size of <strong>1667 x 1667 pixels</strong>.</p><p>However, each file format (PNG, JPEG, and SVG) has its different use cases and benefits. Which one you should use depends on how you plan to use your Branch QR Code.</p><ul><li><strong>PNG</strong>: Recommended for most general use cases. Larger file size. Can support a transparent background if you upload a background image with a transparent background.</li><li><strong>JPEG</strong>: Recommended for most general use cases. This includes digital content and printed materials. Not transparent.</li><li><strong>SVG</strong>: Recommended when being able to resize the image without losing quality is essential. This could include high-quality print materials (posters, flyers, large banners) or certain websites. Can support a transparent background if you upload a background image with a transparent background.</li></ul>',28)])])}const g=a(n,[["render",i]]);export{p as __pageData,g as default};
